-- ============================================================
-- BHT Alarmi: WebGIS inventory import
-- Source: CACTI_Alarmi MapServer Layer 4 (BTS, 1765 sites)
-- Generated: 2026-06-19
-- ============================================================

-- 1. REGIONS (from WebGIS PODRUCJEODRZAVANJA)
CREATE TABLE IF NOT EXISTS gis_regions (
    id          SERIAL PRIMARY KEY,
    code        VARCHAR(20)  UNIQUE NOT NULL,  -- 'TUZLA', 'ZENICA' …
    name        VARCHAR(60)  NOT NULL           -- display name
);

INSERT INTO gis_regions (code, name) VALUES
    ('TUZLA',    'Tuzla'),
    ('ZENICA',   'Zenica'),
    ('SARAJEVO', 'Sarajevo'),
    ('BIHAC',    'Bihać'),
    ('MOSTAR',   'Mostar'),
    ('TRAVNIK',  'Travnik'),
    ('GORAZDE',  'Goražde'),
    ('UNKNOWN',  'Unknown')
ON CONFLICT (code) DO NOTHING;

-- 2. GIS SITES (BTS radio sites from WebGIS Layer 4)
CREATE TABLE IF NOT EXISTS gis_sites (
    id              SERIAL PRIMARY KEY,
    nename          VARCHAR(120) UNIQUE NOT NULL, -- Huawei NE name (e.g. 'ADA')
    lokacija        TEXT,                          -- human-readable location
    region_code     VARCHAR(20)  REFERENCES gis_regions(code),
    ip_address      INET,
    tehnologija     VARCHAR(40),                   -- GSM/LTE/UMTS
    ne_type         VARCHAR(50),                   -- BTS3900, DBS3900…
    product_type    VARCHAR(50),
    lat             DOUBLE PRECISION,
    lon             DOUBLE PRECISION,
    x_coord         DOUBLE PRECISION,              -- projected (HTRS96/TM)
    y_coord         DOUBLE PRECISION,
    band            VARCHAR(30),
    bsc_rnc         VARCHAR(80),
    year_deployed   SMALLINT,
    ne_conn_status  VARCHAR(20)  DEFAULT 'Online',
    gid             BIGINT,
    sid             BIGINT
);

-- Index for fuzzy name matching via pg_trgm
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE INDEX IF NOT EXISTS gis_sites_nename_trgm  ON gis_sites USING gin (nename  gin_trgm_ops);
CREATE INDEX IF NOT EXISTS gis_sites_lokacija_trgm ON gis_sites USING gin (lokacija gin_trgm_ops);

