    ip_address     = EXCLUDED.ip_address,
    lat            = EXCLUDED.lat,
    lon            = EXCLUDED.lon;

-- 3. SITE→GIS mapping (links alarm site_key to gis_sites)
CREATE TABLE IF NOT EXISTS site_gis_map (
    site_key        VARCHAR(120) PRIMARY KEY,  -- alarm system key (Cacti host)
    gis_site_id     INTEGER REFERENCES gis_sites(id),
    match_score     REAL,
    matched_at      TIMESTAMPTZ DEFAULT NOW(),
    verified        BOOLEAN DEFAULT FALSE
);

-- 4. AUTO-POPULATE mapping via pg_trgm fuzzy match
-- Run this after populating your alarm site_keys:
-- (adjust source table/column to your actual alarm schema)
INSERT INTO site_gis_map (site_key, gis_site_id, match_score)
SELECT DISTINCT ON (sk.site_key)
    sk.site_key,
    gs.id,
    similarity(
        regexp_replace(sk.site_key, '^(FTTE|US|TKC|OSS)_', ''),
        gs.nename
    ) AS score
FROM (SELECT DISTINCT site_key FROM alarms) sk
CROSS JOIN LATERAL (
    SELECT id, nename,
           similarity(
               regexp_replace(sk.site_key, '^(FTTE|US|TKC|OSS)_', ''),
               nename
           ) AS sim
    FROM gis_sites
    ORDER BY sim DESC
    LIMIT 1
) gs
WHERE gs.sim > 0.3
ON CONFLICT (site_key) DO NOTHING;

-- 5. ENRICHED VIEW: alarms + GIS data
CREATE OR REPLACE VIEW v_alarms_enriched AS
SELECT
    a.*,
    gs.lokacija,
    gs.region_code,
    gs.lat,
    gs.lon,
    gs.tehnologija,
    gs.ne_type,
    gs.ip_address   AS gis_ip,
    m.match_score,
    m.verified      AS gis_verified
FROM alarms a
LEFT JOIN site_gis_map  m  ON m.site_key   = a.site_key
LEFT JOIN gis_sites     gs ON gs.id        = m.gis_site_id;

-- ============================================================
-- 6. DWDM OPTICAL TRANSPORT NODES (Layer 11, 79 devices)
--    Brands: Coriant (38) + Huawei (41)
--    Includes international backbone nodes (Budapest, Horgoš, Bečej…)
-- ============================================================
CREATE TABLE IF NOT EXISTS gis_dwdm (
    id              SERIAL PRIMARY KEY,
    uredaj          VARCHAR(120) UNIQUE NOT NULL,  -- e.g. 'CORIANT BRKA', 'HUAWEI TUZLA DWDM 1'
    brand           VARCHAR(30),                    -- CORIANT | HUAWEI
    lokacija        VARCHAR(100),                   -- location name
    region_code     VARCHAR(20) REFERENCES gis_regions(code),
    node_type       VARCHAR(20)                     -- CORE | DWDM | NULL
);

